import type { InputStream, Stack } from '@lezer/lr';

import { characterCodes } from '../character-codes.js';
import { getTextFromStream } from './get-text-from-stream.js';
import { isEscaped } from './is-escaped.js';
import { RESERVED_CHARACTERS } from '../../utils/escape-suggestion.js';
import { FreeText } from '../parser.terms.js';

const { ASTERISK, DOLLAR, DOUBLEQUOTE, EOF, SPACE, CLOSING_BRACKET } =
  characterCodes;

// Regex for mathing a potential JSONPath.
// Essentially checks whether there's a JSONRoot followed by at least one valid path.
// Regex + Javascript string escaping = Fun with backslashes.
// https://regex101.com/r/whOdAC/1
const matchJSONPath = new RegExp(
  `^(?:"(?:[^"\\\\*]|\\\\.)*"|(?:[^${RESERVED_CHARACTERS}]|\\\\.)+)\\$(?:.(?:[^${RESERVED_CHARACTERS}]|\\\\.)+|\\["(?:[^"\\\\*]|\\\\.)*"\\])`,
);

const matchValidKeyCharacter = new RegExp(
  `(?:[^${RESERVED_CHARACTERS}]|\\s)+`,
  'i',
);

/**
 * Advance the stream to the end of the FreeText token.
 * Adjust the end accordingly to exclude the previous token in case
 * a free text is followed by a token that requires a filter key.
 * @internal
 */
export function advanceAndAcceptFreeText(
  inputStream: InputStream,
  stack: Stack,
  offset: number,
  startedStringTokenization: boolean,
  lastTokenizationEndIndexCache: WeakMap<Stack, number>,
  excludePreviousToken: boolean = false,
) {
  const stringifiedCandidate = getTextFromStream(inputStream, offset);

  if (stringifiedCandidate === '') {
    return;
  }

  if (matchJSONPath.test(stringifiedCandidate.trim())) {
    lastTokenizationEndIndexCache.set(stack, stack.pos);
    return;
  }

  // To not have the free text be too greedy, we need to track back in certain scenarios.
  // E.g.:
  /*
    a b c = d
    --> Desired outcome: ›a b ‹›c = d‹
    Running the free text tokenizer, the offset is already at 6 when we encounter the "="
    We need to track back 2 position to end the free text before the "c"
   */
  let trackBack = 0;
  let foundValidToken = false;

  // Track back until the previous token is no longer included in the free text.
  // For string tokens, we have to basically reverse the string detection and track back
  // from the closing doublequote until we find a non-escaped opening doublequote.
  if (excludePreviousToken) {
    // TODO: It should be possible to get rid of all that backtracking magic if we somehow manage to store the last "acceptable" position of a free text token when going through the input the first time.
    // Exclude all trailing spaces from the free text.
    while (inputStream.peek(offset + trackBack - 1) === SPACE) {
      trackBack -= 1;
    }

    while (true) {
      const prevCharIndex = offset + trackBack - 1;
      const previousChar = inputStream.peek(prevCharIndex);

      if (
        previousChar === ASTERISK &&
        (inputStream.peek(prevCharIndex - 1) === EOF ||
          // Include asterisk in free text if we expect to exclude a valid token.
          // Since asterisks are not valid inside keys, this is the easiest solution to properly tokenize e.g.
          // "a*" b *=d
          (trackBack === 0 &&
            (stack.context.lastToken === 'expression' ||
              stack.context.lastToken === null)))
      ) {
        trackBack = 0;
        lastTokenizationEndIndexCache.set(stack, stack.pos + offset);
        break;
      }

      if (
        (previousChar === SPACE && !isEscaped(inputStream, prevCharIndex)) ||
        previousChar === EOF
      ) {
        if (!foundValidToken) {
          lastTokenizationEndIndexCache.set(
            stack,
            stack.pos + offset + trackBack,
          );
        }

        break;
      }

      // Always track back an escaped character, including the escape character '\'
      if (isEscaped(inputStream, prevCharIndex)) {
        trackBack -= 1;
      } else if (
        matchValidKeyCharacter.test(String.fromCharCode(previousChar))
      ) {
        foundValidToken = true;
      } else if (previousChar === DOUBLEQUOTE) {
        break;
      } else if (
        previousChar === ASTERISK &&
        inputStream.peek(stack.pos + offset + trackBack - 2) === SPACE
      ) {
        break;
      } else if (foundValidToken) {
        if (previousChar === DOLLAR) {
          trackBack -= 1;
        }
        // If any token is encountered that is not valid in a filter key and we already found something valid before,
        // we abort tracking back and accept the remaining range as free text.
        break;
      }

      trackBack -= 1;
    }
  }

  // Exclude a trailing space if the token is not the last in the input, keeping statements
  // clearly separated. Exception: keep the space when followed by a closing bracket so that
  // inside a group (e.g. "(foo )") the cursor position remains within the key token's range.
  if (
    inputStream.peek(offset + trackBack - 1) === SPACE &&
    inputStream.peek(offset + trackBack) !== -1 &&
    inputStream.peek(offset + trackBack) !== CLOSING_BRACKET
  ) {
    trackBack -= 1;
  }

  const tokenOffset = offset + trackBack;
  if (trackBack === 0) {
    lastTokenizationEndIndexCache.set(stack, stack.pos + tokenOffset);
  }

  if (tokenOffset > 0 || startedStringTokenization) {
    inputStream.advance(tokenOffset);
    inputStream.acceptToken(FreeText);
  }
}
